import json

# We need to find the latest release version for each package name
package_versions = {}

for row in env['data_5']:
    name = row['Name']
    version = row['Version']
    vinfo_str = row['VersionInfo']

    if isinstance(vinfo_str, str):
        vinfo = json.loads(vinfo_str)
    else:
        vinfo = vinfo_str

    if vinfo.get('IsRelease', False):
        ordinal = vinfo.get('Ordinal', 0)

        if name not in package_versions or ordinal > package_versions[name]['ordinal']:
            package_versions[name] = {'version': version, 'ordinal': ordinal}

# Now map back to the top 5 projects
project_to_packages = {}
for row in env['data_2']:
    proj = row['ProjectName']
    pkg = row['Name']
    if proj not in project_to_packages:
        project_to_packages[proj] = set()
    project_to_packages[proj].add(pkg)

results = []
for proj in env['top_5_names']:
    if proj in project_to_packages:
        for pkg in project_to_packages[proj]:
            if pkg in package_versions:
                results.append(f"{pkg}: {package_versions[pkg]['version']}")

print("Final Answer:")
for r in results:
    print(r)

